//! Partitioned-arena recursion schemes for mutually recursive type families.
//!
//! Declare a family with `partition!`, get per-sort arenas with typed IDs
//! and a full suite of stack-safe, memoized folds, unfolds, transforms,
//! and zippers. See the crate-level [`partition!`] macro for usage.

// Allow integration tests and downstream crates to use `::semi_persistent_traversals::` paths
// generated by the proc macro.
extern crate self as semi_persistent_traversals;

pub use rustc_hash::FxBuildHasher;
pub use rustc_hash::FxHashMap;
pub use rustc_hash::FxHashSet;

// ---------------------------------------------------------------------------
// Memo strategy — None (linear scan) vs Vec (dense) vs Map (sparse)
// ---------------------------------------------------------------------------

/// Memoization strategy selector. Controls how traversals allocate their
/// internal tables.
///
/// - [`memo::None`]: No memoization — stack-based traversal without dedup
///   checks. Fastest for trees with no sharing. **Incorrect on DAGs.**
/// - [`memo::Vec`]: O(store_size) allocation, O(1) lookup via array index.
///   Default. Best when the reachable subtree is a large fraction of the
///   store, or when the store is a DAG with sharing.
/// - [`memo::Map`]: O(reachable) allocation, O(1) amortized lookup via hash
///   map. Best when folding a small subtree in a large store.
pub trait MemoStrategy: sealed::Sealed {
    type Memo<V>: MemoOps<V>;
    type Visit: VisitOps;
    type Mapping: MappingOps;
    /// If true, skip memoization checks in fold (stack-based, no dedup).
    const NO_MEMO: bool = false;
}

pub mod memo {
    //! Memoization strategy types.
    //!
    //! ```ignore
    //! use semi_persistent_traversals::memo;
    //! store.with_strategy::<memo::None>().fold(root, alg);  // no memo, stack-based
    //! store.with_strategy::<memo::Vec>().fold(root, alg);   // dense Vec memo
    //! store.with_strategy::<memo::Map>().fold(root, alg);   // sparse hash-map memo
    //! ```

    /// No memoization — stack-based traversal, no dedup. Fastest for trees.
    pub struct None;
    /// Dense memoization — `Vec`-backed tables sized to the full store.
    pub struct Vec;
    /// Sparse memoization — `HashMap`-backed tables sized to reachable nodes.
    pub struct Map;
}

/// Backwards compat aliases.
pub type Dense = memo::Vec;
pub type Sparse = memo::Map;

mod sealed {
    pub trait Sealed {}
    impl Sealed for super::memo::None {}
    impl Sealed for super::memo::Vec {}
    impl Sealed for super::memo::Map {}
}

impl MemoStrategy for memo::None {
    type Memo<V> = DenseMemo<V>;
    type Visit = DenseVisit;
    type Mapping = DenseMapping;
    const NO_MEMO: bool = true;
}

impl MemoStrategy for memo::Vec {
    type Memo<V> = DenseMemo<V>;
    type Visit = DenseVisit;
    type Mapping = DenseMapping;
}

impl MemoStrategy for memo::Map {
    type Memo<V> = SparseMemo<V>;
    type Visit = SparseVisit;
    type Mapping = SparseMapping;
}

// --- MemoOps: Option<V> table ---

pub trait MemoOps<V> {
    fn new(arena_len: usize) -> Self;
    fn get(&self, k: usize) -> Option<&V>;
    fn set(&mut self, k: usize, v: V);
    fn take(&mut self, k: usize) -> Option<V>;
}

pub struct DenseMemo<V>(Vec<Option<V>>);
impl<V> MemoOps<V> for DenseMemo<V> {
    #[inline]
    fn new(len: usize) -> Self {
        Self((0..len).map(|_| None).collect())
    }
    #[inline(always)]
    fn get(&self, k: usize) -> Option<&V> {
        self.0[k].as_ref()
    }
    #[inline(always)]
    fn set(&mut self, k: usize, v: V) {
        self.0[k] = Some(v);
    }
    #[inline]
    fn take(&mut self, k: usize) -> Option<V> {
        self.0[k].take()
    }
}

pub struct SparseMemo<V>(FxHashMap<usize, V>);
impl<V> MemoOps<V> for SparseMemo<V> {
    #[inline]
    fn new(_: usize) -> Self {
        Self(FxHashMap::default())
    }
    #[inline(always)]
    fn get(&self, k: usize) -> Option<&V> {
        self.0.get(&k)
    }
    #[inline(always)]
    fn set(&mut self, k: usize, v: V) {
        self.0.insert(k, v);
    }
    #[inline]
    fn take(&mut self, k: usize) -> Option<V> {
        self.0.remove(&k)
    }
}

// --- VisitOps: bool set ---

pub trait VisitOps {
    fn new(arena_len: usize) -> Self;
    fn visited(&self, k: usize) -> bool;
    fn mark(&mut self, k: usize);
}

pub struct DenseVisit(Vec<bool>);
impl VisitOps for DenseVisit {
    #[inline]
    fn new(len: usize) -> Self {
        Self(vec![false; len])
    }
    #[inline(always)]
    fn visited(&self, k: usize) -> bool {
        self.0[k]
    }
    #[inline(always)]
    fn mark(&mut self, k: usize) {
        self.0[k] = true;
    }
}

pub struct SparseVisit(FxHashSet<usize>);
impl VisitOps for SparseVisit {
    #[inline]
    fn new(_: usize) -> Self {
        Self(FxHashSet::default())
    }
    #[inline(always)]
    fn visited(&self, k: usize) -> bool {
        self.0.contains(&k)
    }
    #[inline(always)]
    fn mark(&mut self, k: usize) {
        self.0.insert(k);
    }
}

// --- MappingOps: usize → usize table ---

pub trait MappingOps {
    fn new(arena_len: usize) -> Self;
    fn get(&self, k: usize) -> usize;
    fn set(&mut self, k: usize, v: usize);
}

pub struct DenseMapping(Vec<usize>);
impl MappingOps for DenseMapping {
    #[inline]
    fn new(len: usize) -> Self {
        Self(vec![0; len])
    }
    #[inline(always)]
    fn get(&self, k: usize) -> usize {
        self.0[k]
    }
    #[inline(always)]
    fn set(&mut self, k: usize, v: usize) {
        self.0[k] = v;
    }
}

pub struct SparseMapping(FxHashMap<usize, usize>);
impl MappingOps for SparseMapping {
    #[inline]
    fn new(_: usize) -> Self {
        Self(FxHashMap::default())
    }
    #[inline(always)]
    fn get(&self, k: usize) -> usize {
        self.0[&k]
    }
    #[inline(always)]
    fn set(&mut self, k: usize, v: usize) {
        self.0.insert(k, v);
    }
}

// ---------------------------------------------------------------------------
// Variadic — pool-backed variable-length child list
// ---------------------------------------------------------------------------

#[derive(Clone, Debug)]
pub enum Variadic<R> {
    Span { start: u32, len: u32 },
    Resolved(smallvec::SmallVec<[R; 4]>),
}

impl<R> Variadic<R> {
    pub fn iter(&self) -> std::slice::Iter<'_, R> {
        match self {
            Variadic::Resolved(v) => v.iter(),
            _ => panic!("unresolved"),
        }
    }
    pub fn len(&self) -> usize {
        match self {
            Variadic::Resolved(v) => v.len(),
            Variadic::Span { len, .. } => *len as usize,
        }
    }
    pub fn is_empty(&self) -> bool {
        self.len() == 0
    }
    pub fn map_all<S>(self, f: &mut impl FnMut(R) -> S) -> Variadic<S> {
        match self {
            Variadic::Resolved(v) => Variadic::Resolved(v.into_iter().map(f).collect()),
            _ => panic!("unresolved"),
        }
    }
    pub fn into_vec(self) -> Vec<R> {
        match self {
            Variadic::Resolved(v) => v.into_vec(),
            _ => panic!("unresolved"),
        }
    }
    /// Get the pool slice indices without allocating. Only valid for Span variant.
    pub fn span_indices<'a>(&self, pool: &'a [usize]) -> &'a [usize] {
        match self {
            Variadic::Span { start, len } => {
                &pool[*start as usize..(*start as usize + *len as usize)]
            }
            Variadic::Resolved(_) => panic!("already resolved"),
        }
    }
}

impl<R> IntoIterator for Variadic<R> {
    type Item = R;
    type IntoIter = std::vec::IntoIter<R>;
    fn into_iter(self) -> Self::IntoIter {
        self.into_vec().into_iter()
    }
}

impl<R> std::ops::Index<usize> for Variadic<R> {
    type Output = R;
    fn index(&self, i: usize) -> &R {
        match self {
            Variadic::Resolved(v) => &v[i],
            _ => panic!("unresolved"),
        }
    }
}

impl<R: PartialEq> PartialEq for Variadic<R> {
    fn eq(&self, other: &Self) -> bool {
        match (self, other) {
            (Variadic::Resolved(a), Variadic::Resolved(b)) => a == b,
            (Variadic::Span { start: s1, len: l1 }, Variadic::Span { start: s2, len: l2 }) => {
                s1 == s2 && l1 == l2
            }
            _ => false,
        }
    }
}
impl<R: Eq> Eq for Variadic<R> {}
impl<R: std::hash::Hash> std::hash::Hash for Variadic<R> {
    fn hash<H: std::hash::Hasher>(&self, state: &mut H) {
        match self {
            Variadic::Resolved(v) => {
                0u8.hash(state);
                v.hash(state);
            }
            Variadic::Span { start, len } => {
                1u8.hash(state);
                start.hash(state);
                len.hash(state);
            }
        }
    }
}

// ---------------------------------------------------------------------------
// HasVariadic — resolve Variadic::Span fields using the pool
// ---------------------------------------------------------------------------

pub trait HasVariadic {
    fn resolve_spans(&mut self, _pool: &[usize]);
}

#[macro_export]
macro_rules! impl_no_variadic {
    ($($ty:ty),* $(,)?) => {
        $(impl $crate::HasVariadic for $ty {
            fn resolve_spans(&mut self, __pool: &[usize]) {}
        })*
    };
}

// ---------------------------------------------------------------------------
// Ann — annotated result for fold_with_history
// ---------------------------------------------------------------------------

/// Annotated result for `fold_with_history`.
///
/// - `value`: the folded result for this node
/// - `children`: store indices of this node's direct children, enabling
///   lookback into grandchildren via the memo tables at those indices.
pub struct Ann<A> {
    pub value: A,
    pub children: smallvec::SmallVec<[usize; 8]>,
}
